import pydicom

print("Testing OD VR...")
try:
    ds = pydicom.Dataset()
    data = b'\x00\x00\x00\x00\x00\x00\x00\x00'
    ds.add_new(0x00660040, 'OD', data)
    print(f"  ✓ OD works with bytes")
except Exception as e:
    print(f"  ✗ Error: {type(e).__name__}: {e}")

print("\nTesting OV VR...")
try:
    ds2 = pydicom.Dataset()
    data = b'\x00\x00\x00\x00\x00\x00\x00\x00'
    ds2.add_new(0x00660040, 'OV', data)
    print(f"  ✓ OV works with bytes")
except Exception as e:
    print(f"  ✗ Error: {type(e).__name__}: {e}")

print("\nTesting OD VR with list (should raise error)...")
try:
    ds3 = pydicom.Dataset()
    data = [1, 2, 3]
    ds3.add_new(0x00660040, 'OD', data)
    print(f"  ✗ Should have raised error but didn't")
except TypeError as e:
    print(f"  ✓ Correctly raised TypeError: {e}")
except Exception as e:
    print(f"  ✗ Wrong error type: {type(e).__name__}: {e}")

print("\nTesting OD VR with bytes containing backslash (should not split)...")
try:
    ds4 = pydicom.Dataset()
    data = b'data\x5Cwith\x5Cbackslashes'
    ds4.add_new(0x00660040, 'OD', data)
    if isinstance(ds4[0x00660040].value, bytes):
        print(f"  ✓ Value is bytes (not split)")
    else:
        print(f"  ✗ Value was split: {type(ds4[0x00660040].value)}")
except Exception as e:
    print(f"  ✗ Error: {type(e).__name__}: {e}")
EOF"}

